  String attribute = "Ben";

  QueryOptions qo = new QueryOptions();
  log.error("  1..................   ");
  // Base filters
  // Filter targetFilter = Filter.eq("IdentityRequest.targetId", "Aaron Nichols");
  Filter operationFilter = Filter.eq("operation", "Add");
  Filter stateFilter = Filter.eq("provisioningState", "Pending");
  Filter notIIQFilter = Filter.ne("name", "IIQ");
  Filter nativeIdentity = Filter.eq("nativeIdentity", "CN=Aaron Nichols,OU=People,OU=Demo,DC=Eshiam,DC=com");
  log.error("  2.............   ");

  // ManagedAttribute join filters
  Filter f = Filter.subquery( "value", ManagedAttribute.class , "value" ,Filter.like("displayName", attribute, Filter.MatchMode.ANYWHERE));
  log.error("  3.............  ");
  // Combine filters
  Filter finalFilter = Filter.and(targetFilter,operationFilter,stateFilter,notIIQFilter,f);
  log.error("  4...........   ");

  // Add joins (VERY IMPORTANT)
  qo.addFilter(finalFilter);
  log.error("  5.............   ");
  //qo.addFilter(Filter.join("IdentityRequest.id", "IdentityRequest.id"));
  qo.addFilter(Filter.join("value", "ManagedAttribute.value"));
  qo.addFilter(Filter.join("application", "ManagedAttribute.application.name"));
  log.error("  6................  ");
  log.error(" Filter ...........:: "+qo);

  List identityRequests = context.getObjects(IdentityRequestItem.class, qo);


  return identityRequests;


