  import sailpoint.object.*;
  import sailpoint.api.*;
  import java.util.*;

  // Define the DNs that are no longer in your target system
  List stringsToRemove = Arrays.asList(new String[]{
    "CN=Cost-SavingsAnalysis,OU=Groups,OU=Demo,DC=Eshiam,DC=com",
    "CN=customerDataCenter,OU=Groups,OU=Demo,DC=Eshiam,DC=com"
  });

  // 1. Fetch your specific bundle by name
  Bundle bundle = context.getObjectByName(Bundle.class, "Testing");

  if (bundle != null) {
    List profiles = bundle.getProfiles();
    if (profiles != null) {
      List toDelete = new ArrayList();

      for (Profile profile : profiles) {
        // Check the constraints for the specific values
        String xml = profile.toXml();
        for (String dn : stringsToRemove) {
          if (xml.contains(dn)) {
            toDelete.add(profile);
            break; 
          }
        }
      }

      // 2. Remove the matching profiles from the Bundle
      for (Profile p : toDelete) {
        bundle.remove(p);
        log.warn("Removing profile " + p.getId() + " from Bundle: " + bundle.getName());
      }

      // 3. Save the Bundle and commit
      context.saveObject(bundle);
      context.commitTransaction();
      return "Profiles removed successfully.";
    }
  }
  return "Bundle not found or no profiles to remove.";







