  return context.decrypt("1:ACP:1wZ3+L0S5zxxqNAzkdZjSWYsYixrZwFrthZM37L5NDL90Knw7GNnnKihCiLgKhq8dIV0drzo2D8Ds7we61NUAg==");



  {
    Log tlog = LogFactory.getLog("rule.sp.rule.ToyotaAtldapIdTransformation");    
    if (tlog.isTraceEnabled()) {
      tlog.trace("TATLDAPT::001-Entering Toyota AtldapId Transformation");
      tlog.trace( "TATLDAPT::002-with atldapid value = "+"value" );
    }

    IdentityService idService = new IdentityService(context);
    Identity identity = context.getObjectByName(Identity.class,"Mahesh Nattali");;
    Application orgLdap = null;
    Application workerDB = context.getObjectByName(Application.class , "ActiveDirectory");;
    Link link = null;
    String value = "mahesh.nattali@eshiam.comrule";

    if (workerDB != null) {
      List workerDBLinks = idService.getLinks(identity,workerDB);
      if (Util.nullSafeSize(workerDBLinks)>0) {
        link = workerDBLinks.get(0);
      }
    }


    String returnValue = link != null?link.getAttribute("mail"):identity.getEmail() ;  
    log.error(" returnValue value  :  "+returnValue);



    try {
      orgLdap = context.getObjectByName(Application.class , "IntConApplication");
      if (orgLdap != null) {
        List orgLdapLinks = idService.getLinks(identity,orgLdap);
        if (Util.nullSafeSize(orgLdapLinks)>0) {
          Link orgLdapLink = orgLdapLinks.get(0);
          if (orgLdapLink != null && !orgLdapLink.isDisabled()) { 
            String atldapUserValue = orgLdapLink.getAttribute("atldapUser");
            log.error(" atldapUser value  :  "+atldapUserValue);
            if (atldapUserValue.equalsIgnoreCase("Y")){
              returnValue = value;
            }
          }
        }
      }
    } catch (Exception e) {
      throw new GeneralException("TAAR::003-ERROR for User: " + identity.getName() + " Error Message: An exception was thrown while attempting to process AD After Provisioning rule: " + e.getMessage());          
    } finally {
      if (tlog.isTraceEnabled()) {
        tlog.trace("TATLDAPT::004-Entering Toyota AtldapId Transformation");
        tlog.trace( "TATLDAPT::005-with atldapid value = "+value );
      }
      context.decache(orgLdap);
      context.decache(workerDB);
    }

    if (tlog.isTraceEnabled()) {
      tlog.trace("TATLDAPT::006-Exiting Toyota AtldapId Transformation");
      tlog.trace( "TATLDAPT::007-with atldapid returnValue = "+returnValue );
    }        
    return returnValue;

  }

